async (params, browser) => {
  // Open Discord channel
  await browser.open(`${params.channel_url}`)

  // Wait for message input
  await browser.waitForSelector('div[role=\'textbox\'][contenteditable=\'true\']', 15000)

  // Let channel load
  await browser.wait(1500)

  // Type message
  const type_message = await browser.evaluate(`const el = document.querySelector('div[role="textbox"][contenteditable="true"]'); if (!el) throw new Error('Message input not found'); el.focus(); await new Promise(r => setTimeout(r, 200)); document.execCommand('insertText', false, params.message); el.dispatchEvent(new Event('input', {bubbles: true})); return { typed: true }`)

  await browser.wait(500)

  // Press Enter to send
  const result = await browser.evaluate(`const el = document.querySelector('div[role="textbox"][contenteditable="true"]'); if (el) { el.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); } return { success: true, message: 'Message sent' }`)

  await browser.wait(1500)

  return result
}
